import React from 'react';
import { Helmet } from 'react-helmet-async';
import { useAuth } from '../../context/AuthContext';

export default function AccountProfilePage() {
  const { user } = useAuth();

  return (
    <div>
      <Helmet>
        <title>Profile | Nova Shop</title>
      </Helmet>
      <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Profile</h2>
      <p style={{ color: 'var(--gray)', marginBottom: '1rem' }}>
        Name: <strong>{user?.name}</strong>
        <br />
        Email: <strong>{user?.email}</strong>
      </p>
      <p style={{ color: 'var(--gray)', maxWidth: 480 }}>
        Profile editing will use <code>PATCH /api/auth/profile</code> when available.
      </p>
    </div>
  );
}
